package main

import "fmt"



// x: número que está sendo testado
// div: divisor que está sendo testado
func eh_primo(x int, div int) bool {
	x1 , div1 := x, div
	if  x1 == 2{
	return true;
	}
	if x1 % div1 == 0 || x1 == 1{
	return false;
	}else{
		if div1*div1 > x1 {
			return true
		}
        eh_primo(x1,div1 + 1)
		return true
	}
}

func main() {
	var x int
	fmt.Scan(&x)
	if eh_primo(x, 2) {
		fmt.Println("true")
	} else {
		fmt.Println("false")
	}
}
